// Loop from 1 to 10 using a counter variable i
for (int i = 1; i <= 10; i++) {
    // Calculate 5 times the current number
    int product = 5 * i;
    // Print each line of the table
    System.out.println("5 x " + i + " = " + product);
}
// Expected output:
// 5 x 1 = 5
// 5 x 2 = 10
// 5 x 3 = 15
// ... continues to 5 x 10 = 50
